impl.spec_text:
trait Tr1 { }
trait Tr2 { }

struct X<T> { a: T }

impl<T: Tr2> X<T> {
    #[verifier::external]
    fn new(a: T) -> Self
        where T: Tr1
    {
        X { a: a }
    }
}

#[verifier::external_fn_specification]
fn ex_X_new<T: Tr1 + Tr2>(a: T) -> (res: X<T>)
    ensures res.a == a,
{
    X::<T>::new(a)
}

struct Foo(u8);
impl Tr1 for Foo { }
impl Tr2 for Foo { }

impl.impl_text:
fn test() {
    let x = X::<Foo>::new(Foo(5));
    assert(x.a == Foo(5));
}
